// Temporary stub module for ExpoLinking
// Replace this with proper expo-linking installation when needed

import ExpoModulesCore

public final class ExpoLinkingModule: Module {
  public func definition() -> ModuleDefinition {
    Name("ExpoLinking")
    
    Constants {
      return [
        "initialURL": nil as String?
      ]
    }
    
    AsyncFunction("getInitialURL") { () -> String? in
      // Return nil - initial URL would be handled by the app delegate
      // This is a stub implementation
      return nil
    }
    
    AsyncFunction("canOpenURL") { (url: String) async -> Bool in
      guard let urlObj = URL(string: url) else {
        return false
      }
      return await UIApplication.shared.canOpenURL(urlObj)
    }
    
    AsyncFunction("openURL") { (url: String) async throws in
      guard let urlObj = URL(string: url) else {
        throw Exception(name: "ERR_LINKING_INVALID_URL", description: "Invalid URL: \(url)")
      }
      await UIApplication.shared.open(urlObj, options: [:])
    }
    
    AsyncFunction("addEventListener") { (eventName: String) in
      // Stub - do nothing
      // Real implementation would listen for URL events
    }
    
    AsyncFunction("removeEventListener") { (eventName: String) in
      // Stub - do nothing
      // Real implementation would remove URL event listeners
    }
    
    AsyncFunction("createURL") { (path: String, queryParams: [String: String]?) -> String in
      // Return a basic URL format
      var urlString = "exp://\(path)"
      
      if let params = queryParams, !params.isEmpty {
        let queryString = params.map { "\($0.key)=\($0.value)" }.joined(separator: "&")
        urlString += "?\(queryString)"
      }
      
      return urlString
    }
    
    AsyncFunction("parse") { (url: String) -> [String: Any?] in
      guard let urlObj = URL(string: url) else {
        return [:]
      }
      
      var queryParams: [String: String] = [:]
      if let query = urlObj.query {
        let components = query.components(separatedBy: "&")
        for component in components {
          let pair = component.components(separatedBy: "=")
          if pair.count == 2 {
            queryParams[pair[0]] = pair[1]
          }
        }
      }
      
      return [
        "scheme": urlObj.scheme,
        "hostname": urlObj.host,
        "path": urlObj.path,
        "queryParams": queryParams
      ]
    }
    
    AsyncFunction("parseURL") { (url: String) -> [String: Any?] in
      guard let urlObj = URL(string: url) else {
        return [:]
      }
      
      var queryParams: [String: String] = [:]
      if let query = urlObj.query {
        let components = query.components(separatedBy: "&")
        for component in components {
          let pair = component.components(separatedBy: "=")
          if pair.count == 2 {
            queryParams[pair[0]] = pair[1]
          }
        }
      }
      
      return [
        "scheme": urlObj.scheme,
        "hostname": urlObj.host,
        "path": urlObj.path,
        "queryParams": queryParams
      ]
    }
  }
}
